# Idempotent indexing: skip chunks that are already indexed
# Use content_hash payload field to detect duplicates

import hashlib
from qdrant_client.models import Filter, FieldCondition, MatchValue

def chunk_hash(text: str) -> str:
    return hashlib.md5(text.encode()).hexdigest()[:16]

def is_already_indexed(qdrant, collection: str, text: str) -> bool:
    h = chunk_hash(text)
    results, _ = qdrant.scroll(
        collection_name=collection,
        scroll_filter=Filter(must=[
            FieldCondition(key='content_hash', match=MatchValue(value=h))
        ]),
        limit=1,
        with_payload=False,
        with_vectors=False,
    )
    return len(results) > 0

def index_if_new(qdrant, collection, voyage_client, chunks):
    new_chunks = [
        c for c in chunks
        if not is_already_indexed(qdrant, collection, c)
    ]
    if not new_chunks:
        print('All chunks already indexed, skipping')
        return 0
    result = voyage_client.embed(new_chunks, model='voyage-3', input_type='document')
    # ... upsert only new_chunks
    return len(new_chunks)
